37	EnterAutomaticScopeGuard::EnterAutomaticScopeGuard(EvalContext &context, const ast::Scope *scope)
38		: context(context), scope(scope)
39	{
40		if (scope) {
41			++context.scope_nest_level[scope];
42		}
43	}
44	
45	EnterAutomaticScopeGuard::~EnterAutomaticScopeGuard()
46	{
47		if (scope) {
48			auto new_nest_level = --context.scope_nest_level.at(scope);
49			log_assert(new_nest_level >= 0);
50			if (new_nest_level == 0)
51				context.scope_nest_level.erase(scope);
52		}
53	}
54	
55	RegisterEscapeConstructGuard::RegisterEscapeConstructGuard(ProceduralContext &context,
56			EscapeConstructKind kind, const ast::SubroutineSymbol *subroutine)
57		: flag(Variable::escape_flag(context.flag_counter++)), context(context)
58	{
59		assert(kind == EscapeConstructKind::FunctionBody);
60		context.escape_stack.emplace_back();
61		auto &construct = context.escape_stack.back();
62		construct.kind = kind;
63		construct.subroutine = subroutine;
64		construct.flag = flag;
65		context.do_simple_assign(subroutine->location, flag, RTLIL::S0, true);
66	}
67	
68	RegisterEscapeConstructGuard::RegisterEscapeConstructGuard(
69			ProceduralContext &context, EscapeConstructKind kind, const ast::Statement *statement)
70		: flag(Variable::escape_flag(context.flag_counter++)), context(context)
71	{
72		log_assert(kind == EscapeConstructKind::Loop || kind == EscapeConstructKind::LoopBody);
73		context.escape_stack.emplace_back();
74		auto &construct = context.escape_stack.back();
75		construct.kind = kind;
76		construct.flag = flag;
77		context.do_simple_assign(statement->sourceRange.start(), flag, RTLIL::S0, true);
78	}
